#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100001
#define INF 0x3f3f3f3f
int n, m;
int dist[MAX];
int queue[MAX];
int front, rear;
int visited[MAX];
int adj[MAX][MAX];
void bfs(int start) {
    int i, j;
    for (i = 1; i <= n; i++) {
        dist[i] = INF;
        visited[i] = 0;
    }
    dist[start] = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (i = 1; i <= n; i++) {
            if (adj[u][i] && !visited[i]) {
                dist[i] = dist[u] + 1;
                queue[rear++] = i;
                visited[i] = 1;
            }
        }
    }
}
int main() {
    int i, j, u, v;
    scanf("%d", &n);
    for (i = 1; i < n; i++) {
        scanf("%d %d", &u, &v);
        adj[u][v] = adj[v][u] = 1;
    }
    scanf("%d", &m);
    for (i = 1; i <= m; i++) {
        scanf("%d %d", &u, &v);
        bfs(u);
        printf("%d\n", dist[v] == INF ? -1 : dist[v]);
    }
    return 0;
}

