#include <iostream>
#include <queue>
#include <vector>
using namespace std;
#define MAX 100001
#define INF 0x3f3f3f3f
int n, m;
int dist[MAX];
bool visited[MAX];
vector<int> adj[MAX];
void bfs(int start) {
    queue<int> q;
    for (int i = 1; i <= n; i++) {
        dist[i] = INF;
        visited[i] = false;
    }
    dist[start] = 0;
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int i = 0; i < adj[u].size(); i++) {
            int v = adj[u][i];
            if (!visited[v]) {
                dist[v] = dist[u] + 1;
                q.push(v);
                visited[v] = true;
            }
        }
    }
}
int main() {
    int i, j, u, v;
    cin >> n;
    for (i = 1; i < n; i++) {
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    cin >> m;
    for (i = 1; i <= m; i++) {
        cin >> u >> v;
        bfs(u);
        cout << (dist[v] == INF ? -1 : dist[v]) << endl;
