import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MAX = 100001;
    static final int INF = 0x3f3f3f3f;
    static int n, m;
    static int[] dist = new int[MAX];
    static boolean[] visited = new boolean[MAX];
    static int[][] adj = new int[MAX][MAX];
    public static void bfs(int start) {
        Queue<Integer> q = new LinkedList<>();
        for (int i = 1; i <= n; i++) {
            dist[i] = INF;
            visited[i] = false;
        }
        dist[start] = 0;
        q.add(start);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int i = 1; i <= n; i++) {
                if (adj[u][i] == 1 && !visited[i]) {
                    dist[i] = dist[u] + 1;
                    q.add(i);
                    visited[i] = true;
                }
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        for (int i = 1; i < n; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            adj[u][v] = adj[v][u] = 1;
        }
        m = sc.nextInt();
        for (int i = 1; i <= m; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            bfs(u);
            System.out.println(dist[v] == INF ? -1 : dist[v]);
        }
    }
}

